class extends require_factory.WorkOS {
	/** @override */
	createHttpClient(options, userAgent) {
		const headers = {};
		const configHeaders = options.config?.headers;
		if (configHeaders) if (configHeaders instanceof Headers) configHeaders.forEach((v, k) => headers[k] = v);
		else if (Array.isArray(configHeaders)) configHeaders.forEach(([k, v]) => headers[k] = v);
		else Object.assign(headers, configHeaders);
		headers["User-Agent"] = userAgent;
		if (this.key) headers["Authorization"] = `Bearer ${this.key}`;
		const opts = {
			...options.config,
			timeout: options.timeout,
			headers
		};
		return new require_factory.FetchHttpClient(this.baseURL, opts, options.fetchFn);
	}
	/** @override */
	createWebhookClient() {
		return new require_factory.Webhooks(this.getCryptoProvider());
	}
	getCryptoProvider() {
		return new require_factory.SubtleCryptoProvider();
	}
	/** @override */
	createActionsClient() {
		return new require_factory.Actions(this.getCryptoProvider());
	}
	/** @override */
	emitWarning(warning) {
		return process.emitWarning(warning, "WorkOS");
	}
}

